#include<bits/stdc++.h>
using namespace std;
long long n,ww;
long long dp[1001],w[10001],v[1001][2];
int main(){
	cin>>n>>ww;
	for(int i=1;i<=n;i++){
		cin>>v[i][0]>>v[i][1]>>w[i];
	}
	for(int i=1;i<=n;i++){
		for(int j=ww;j>=0;j--){
			if(w[i]<=j)	dp[j]=max(dp[j]+v[i][0],dp[j-w[i]]+v[i][1]);
			else dp[j]=dp[j]+v[i][0];

		}
	}
	cout<<dp[ww]*5;
	return 0;
}
